SELECT
    p.id as id,
    p.slug as slug,
    p.title as title,
    p.page_type as pageType,
    p.published as published,
    p.published_at as publishedAt
FROM cms_pages p

    AND p.id = #{id}
    AND p.slug LIKE CONCAT('%', #{slug}, '%')
    AND p.title LIKE CONCAT('%', #{title}, '%')
    AND p.page_type = #{pageType}
    AND p.published = #{published}
    AND p.published_at >= #{startDate}
    AND p.published_at <= #{endDate}

${orderby} ${pagination}

SELECT count(*)
FROM cms_pages p

    AND p.id = #{id}
    AND p.slug LIKE CONCAT('%', #{slug}, '%')
    AND p.title LIKE CONCAT('%', #{title}, '%')
    AND p.page_type = #{pageType}
    AND p.published = #{published}
    AND p.published_at >= #{startDate}
    AND p.published_at <= #{endDate}

SELECT
    b.id as id,
    b.name as name,
    b.image_url as imageUrl,
    b.position as position,
    b.active as active,
    b.created_time as createdAt
FROM banners b

    AND b.id = #{id}
    AND b.name LIKE CONCAT('%', #{name}, '%')
    AND b.position = #{position}
    AND b.active = #{active}
    AND b.created_time >= #{startDate}
    AND b.created_time <= #{endDate}

${orderby} ${pagination}

SELECT count(*)
FROM banners b

    AND b.id = #{id}
    AND b.name LIKE CONCAT('%', #{name}, '%')
    AND b.position = #{position}
    AND b.active = #{active}
    AND b.created_time >= #{startDate}
    AND b.created_time <= #{endDate}
